SET LAST_LOGIN_DATETIME = NOW()
WHERE SEQ = #{seq}

mapper.select:
SELECT SEQ, USER_ID , PASSWORD_RESET, LAST_LOGIN_DATETIME , CREATE_DATETIME, CREATE_IDX , UPDATE_DATETIME, UPDATE_IDX FROM TB_USER WHERE 1 = 1 AND DELETED = 0
AND USER_ID LIKE CONCAT('%', #{searchValue}, '%')
ORDER BY USER_ID LIMIT #{limit} OFFSET #{offset}
